  "inlineSchema": "// Prisma Schema for PrecificaPro (Marketplace Pricing SaaS)\n// Configured to run on PostgreSQL for production SaaS.\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// 1. Companies Table\nmodel Company {\n  id         String   @id @default(uuid())\n  nome       String\n  email      String\n  telefone   String\n  plano      String   @default(\"pro\") // \"pro\", \"master\"\n  status     String   @default(\"ativo\") // \"ativo\", \"bloqueado\"\n  created_at DateTime @default(now())\n\n  users            User[]\n  subscription     Subscription? // 1-to-1 SaaS Subscription relation\n  products         Product[]\n  alerts           Alert[]\n  pricing_history  PricingHistory[]\n  production_costs ProductionCost[]\n\n  @@map(\"companies\")\n}\n\n// 2. Users Table\nmodel User {\n  id         String   @id @default(uuid())\n  company_id String\n  nome       String\n  email      String   @unique\n  senha      String // bcrypt hashed password\n  role       String   @default(\"cliente\") // \"admin\" (Admin Master), \"cliente\" (Client)\n  created_at DateTime @default(now())\n\n  company Company @relation(fields: [company_id], references: [id], onDelete: Cascade)\n\n  @@map(\"users\")\n}\n\n// 3. Subscriptions Table (Asaas Billing & Gating)\nmodel Subscription {\n  id                    String    @id @default(uuid())\n  company_id            String    @unique // Unique for 1-to-1 mapping\n  plan                  String    @default(\"pro\") // \"pro\", \"free\"\n  status                String    @default(\"trial\") // \"trial\", \"active\", \"pending\", \"expired\", \"blocked\", \"cancelled\"\n  asaas_customer_id     String? // Asaas Customer ID (cus_...)\n  asaas_subscription_id String? // Asaas Subscription ID (sub_...)\n  trial_ends_at         DateTime // Grace period threshold\n  expires_at            DateTime? // Next payment due expiration date\n  manual_release        Boolean   @default(false) // Admin override bypass\n  created_at            DateTime  @default(now())\n\n  company Company @relation(fields: [company_id], references: [id], onDelete: Cascade)\n\n  @@map(\"subscriptions\")\n}\n\n// 4. Products Table\nmodel Product {\n  id             String   @id @default(uuid())\n  company_id     String\n  nome           String\n  sku            String\n  marketplace    String // \"mercado_livre\", \"shopee\", \"amazon\", \"magalu\", \"shein\", \"tiktok_shop\", \"olist\", \"webcontinental\"\n  custo_tipo     String   @default(\"revenda\") // \"revenda\", \"fabricacao\", \"confeccao\"\n  detalhes_custo String? // JSON string holding details of materials, yields, outsourced costs\n  custo          Float // Custo do produto calculado\n  frete          Float // Frete de envio\n  embalagem      Float    @default(0.0)\n  imposto        Float    @default(0.0) // Imposto em %\n  comissao       Float    @default(0.0) // Comissão em %\n  margem         Float    @default(0.0) // Margem desejada em %\n  preco_atual    Float // Preço praticado\n  preco_ideal    Float    @default(0.0)\n  lucro          Float    @default(0.0)\n  status         String   @default(\"ativo\")\n  created_at     DateTime @default(now())\n\n  company Company @relation(fields: [company_id], references: [id], onDelete: Cascade)\n\n  production_cost_id String?\n  production_cost    ProductionCost? @relation(fields: [production_cost_id], references: [id], onDelete: SetNull)\n\n  @@map(\"products\")\n}\n\n// 5. Pricing History Audit Table\nmodel PricingHistory {\n  id             String   @id @default(uuid())\n  company_id     String\n  product_id     String\n  preco_anterior Float\n  preco_novo     Float\n  lucro_anterior Float\n  lucro_novo     Float\n  created_at     DateTime @default(now())\n\n  company Company @relation(fields: [company_id], references: [id], onDelete: Cascade)\n\n  @@map(\"pricing_history\")\n}\n\n// 6. Alerts Table\nmodel Alert {\n  id         String   @id @default(uuid())\n  company_id String\n  tipo       String // \"prejuizo\", \"margem_baixa\", \"desatualizado\", \"taxa_alta\"\n  mensagem   String\n  status     String   @default(\"nao_lido\") // \"lido\", \"nao_lido\"\n  created_at DateTime @default(now())\n\n  company Company @relation(fields: [company_id], references: [id], onDelete: Cascade)\n\n  @@map(\"alerts\")\n}\n\n// 7. Production Costs (Fichas de Custo)\nmodel ProductionCost {\n  id             String   @id @default(uuid())\n  company_id     String\n  sku            String\n  nome           String\n  custo_tipo     String // \"fabricacao\" or \"confeccao\"\n  detalhes_custo String // JSON string for fabrics, raw materials, labor, services\n  custo_total    Float\n  created_at     DateTime @default(now())\n\n  company  Company   @relation(fields: [company_id], references: [id], onDelete: Cascade)\n  products Product[] // Link to products that consume this cost\n\n  @@unique([company_id, sku])\n  @@map(\"production_costs\")\n}\n",
